// ── Code - Transcribe Audio (V12) ────────────────────────────────────────────
// Usa a URL pública do Supabase Storage (resolvida pelo nó anterior)
// para baixar o áudio e transcrever via OpenAI Whisper.

const canonical = $input.first().json;
const OPENAI_KEY = 'OPENAI_API_KEY_PLACEHOLDER';

if (canonical.content_type !== 'audio') {
  return [{ json: canonical }];
}

// Só tenta transcrever se media_url for URL pública do Supabase (download confiável)
if (!canonical.media_url || !canonical.media_url.includes('supabase.co/storage')) {
  return [{ json: canonical }];
}

try {
  // Baixa o áudio do Supabase Storage
  const audioRes = await fetch(canonical.media_url);
  if (!audioRes.ok) return [{ json: canonical }];

  const arrayBuf = await audioRes.arrayBuffer();
  const binary   = Buffer.from(arrayBuf);

  // Detecta extensão pela URL
  const urlPath  = canonical.media_url.split('?')[0];
  const urlExt   = (urlPath.split('.').pop() || 'ogg').toLowerCase();
  const mimeMap  = {
    ogg: 'audio/ogg',
    mp3: 'audio/mpeg',
    m4a: 'audio/mp4',
    aac: 'audio/aac',
    wav: 'audio/wav',
  };
  const mime = mimeMap[urlExt] || 'audio/ogg';

  const formData = new FormData();
  const blob     = new Blob([binary], { type: mime });
  formData.append('file', blob, `audio.${urlExt}`);
  formData.append('model', 'whisper-1');
  formData.append('language', 'pt');

  const res = await fetch('https://api.openai.com/v1/audio/transcriptions', {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${OPENAI_KEY}` },
    body: formData,
  });

  if (!res.ok) return [{ json: canonical }];

  const result        = await res.json();
  const transcription = (result.text || '').trim();

  if (!transcription) return [{ json: canonical }];

  return [{ json: { ...canonical, content: transcription } }];

} catch (_) {
  return [{ json: canonical }];
}
